import{_ as e,o as r,c as a,ak as d}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"数据库性能优化","description":"","frontmatter":{},"headers":[],"relativePath":"high-performance/db/index.md","filePath":"high-performance/db/index.md","lastUpdated":1774360456000}'),h={name:"high-performance/db/index.md"};function i(o,t,l,n,s,p){return r(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="数据库性能优化" tabindex="-1">数据库性能优化 <a class="header-anchor" href="#数据库性能优化" aria-label="Permalink to “数据库性能优化”">​</a></h1><p>凌晨 2 点，你被一阵急促的告警铃声惊醒。</p><p>监控系统显示：数据库 CPU 飙升至 98%，响应时间从 50ms 飙升到 8 秒。用户开始疯狂投诉，订单量断崖式下跌。</p><p>你赶紧登录数据库，执行 <code>show processlist</code>——好家伙，几百个慢查询堵在那里。其中一条 SQL 跑了整整 45 秒，扫描了全表 300 万行数据。</p><p>你冷汗直流：这 SQL 昨天还好好的，今天怎么突然慢了？</p><p>这是每一个后端工程师都可能遇到的真实场景。<strong>数据库是大多数系统的性能瓶颈所在，而数据库优化，是每个工程师的必修课。</strong></p><p>本模块系统讲解 SQL 优化、MySQL 调优、Redis 性能优化、NoSQL 与搜索引擎优化，助你成为数据库性能专家。</p><hr><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><h3 id="sql-优化与执行计划" tabindex="-1">SQL 优化与执行计划 <a class="header-anchor" href="#sql-优化与执行计划" aria-label="Permalink to “SQL 优化与执行计划”">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>简介</th></tr></thead><tbody><tr><td><a href="/high-performance/db/sql-slow">慢查询定位与分析</a></td><td>开启慢查询日志，定位问题 SQL</td></tr><tr><td><a href="/high-performance/db/explain">EXPLAIN 执行计划解读</a></td><td>读懂执行计划每个字段的含义</td></tr><tr><td><a href="/high-performance/db/index-optimize">索引优化全攻略</a></td><td>索引设计原则与最佳实践</td></tr><tr><td><a href="/high-performance/db/join-optimize">JOIN 优化与 MRR</a></td><td>JOIN 原理与优化技巧</td></tr><tr><td><a href="/high-performance/db/filesort-temporary">filesort 与临时表</a></td><td>何时产生，如何避免</td></tr><tr><td><a href="/high-performance/db/pagination">分页查询优化</a></td><td>深分页问题的解决方案</td></tr><tr><td><a href="/high-performance/db/count-optimize">COUNT(*) 优化</a></td><td>飞龙表的处理方式</td></tr><tr><td><a href="/high-performance/db/batch-optimize">批量操作优化</a></td><td>批量插入、更新、删除</td></tr></tbody></table><h3 id="mysql-调优" tabindex="-1">MySQL 调优 <a class="header-anchor" href="#mysql-调优" aria-label="Permalink to “MySQL 调优”">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>简介</th></tr></thead><tbody><tr><td><a href="/high-performance/db/mysql-config">MySQL 配置参数调优</a></td><td>核心配置项解读与调优</td></tr><tr><td><a href="/high-performance/db/connection-pool">连接池配置与调优</a></td><td>连接池大小计算与配置</td></tr><tr><td><a href="/high-performance/db/concurrency">并发控制：MVCC 与锁</a></td><td>事务隔离与锁机制</td></tr><tr><td><a href="/high-performance/db/read-write">读写分离实战</a></td><td>主从复制与延迟处理</td></tr><tr><td><a href="/high-performance/db/hot-row">热点行问题解决</a></td><td>高并发下的行锁竞争</td></tr></tbody></table><h3 id="redis-性能优化" tabindex="-1">Redis 性能优化 <a class="header-anchor" href="#redis-性能优化" aria-label="Permalink to “Redis 性能优化”">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>简介</th></tr></thead><tbody><tr><td><a href="/high-performance/db/redis-big-key">Redis 大 Key 问题</a></td><td>大 Key 的识别与处理</td></tr><tr><td><a href="/high-performance/db/redis-hot-key">Redis 热 Key 问题</a></td><td>热 Key 的发现与解决</td></tr><tr><td><a href="/high-performance/db/redis-memory">Redis 内存优化</a></td><td>内存碎片、存储优化</td></tr><tr><td><a href="/high-performance/db/redis-persistence">Redis 持久化策略</a></td><td>RDB、AOF 详解与选择</td></tr><tr><td><a href="/high-performance/db/redis-pipeline">Redis 管道与事务</a></td><td>批量操作优化</td></tr><tr><td><a href="/high-performance/db/redis-cluster-optimize">Redis 集群优化</a></td><td>集群选型与运维</td></tr></tbody></table><h3 id="nosql-与搜索引擎" tabindex="-1">NoSQL 与搜索引擎 <a class="header-anchor" href="#nosql-与搜索引擎" aria-label="Permalink to “NoSQL 与搜索引擎”">​</a></h3><table tabindex="0"><thead><tr><th>文档</th><th>简介</th></tr></thead><tbody><tr><td><a href="/high-performance/db/mongodb-optimize">MongoDB 优化实战</a></td><td>索引设计、查询优化</td></tr><tr><td><a href="/high-performance/db/es-query">ES 查询优化</a></td><td>分片策略、查询缓存</td></tr><tr><td><a href="/high-performance/db/es-write">ES 写入优化</a></td><td>批量写入、刷新策略</td></tr><tr><td><a href="/high-performance/db/clickhouse">ClickHouse 高性能实战</a></td><td>列式存储与向量化执行</td></tr></tbody></table><hr><h2 id="数据库优化的三个层次" tabindex="-1">数据库优化的三个层次 <a class="header-anchor" href="#数据库优化的三个层次" aria-label="Permalink to “数据库优化的三个层次”">​</a></h2><h3 id="第一层-sql-优化" tabindex="-1">第一层：SQL 优化 <a class="header-anchor" href="#第一层-sql-优化" aria-label="Permalink to “第一层：SQL 优化”">​</a></h3><p>SQL 优化是最基础也是最重要的优化手段。很多性能问题，只需要一条索引就能解决。</p><p>关键点：</p><ul><li>学会读 <code>EXPLAIN</code> 执行计划</li><li>理解索引失效的常见场景</li><li>避免全表扫描和filesort</li><li>控制 JOIN 的复杂度</li></ul><h3 id="第二层-mysql-调优" tabindex="-1">第二层：MySQL 调优 <a class="header-anchor" href="#第二层-mysql-调优" aria-label="Permalink to “第二层：MySQL 调优”">​</a></h3><p>当 SQL 层面优化到极致后，下一步是 MySQL 本身的调优。</p><p>关键点：</p><ul><li>合理配置缓冲池大小</li><li>选择合适的隔离级别</li><li>优化锁策略，减少锁竞争</li><li>利用读写分离分担压力</li></ul><h3 id="第三层-架构优化" tabindex="-1">第三层：架构优化 <a class="header-anchor" href="#第三层-架构优化" aria-label="Permalink to “第三层：架构优化”">​</a></h3><p>架构层面的优化，解决的是更深层次的问题。</p><p>关键点：</p><ul><li>分库分表：水平拆分突破单库瓶颈</li><li>Redis 缓存：热点数据缓存减少数据库压力</li><li>搜索引擎：复杂查询交给 ES</li><li>分析型数据库：OLAP 场景用 ClickHouse</li></ul><hr><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><h3 id="入门-从-sql-优化开始" tabindex="-1">入门：从 SQL 优化开始 <a class="header-anchor" href="#入门-从-sql-优化开始" aria-label="Permalink to “入门：从 SQL 优化开始”">​</a></h3><p>建议先学习<strong>慢查询定位</strong>和<strong>执行计划解读</strong>。</p><p>这是数据库优化的基础。学会定位慢 SQL，读懂执行计划，你就迈出了数据库优化的第一步。</p><h3 id="进阶-深入-mysql-机制" tabindex="-1">进阶：深入 MySQL 机制 <a class="header-anchor" href="#进阶-深入-mysql-机制" aria-label="Permalink to “进阶：深入 MySQL 机制”">​</a></h3><p>学习<strong>索引优化</strong>、<strong>JOIN 原理</strong>、<strong>并发控制</strong>等核心知识点。</p><p>这些内容需要深入理解原理，不能只记结论。建议配合实际案例，边学边练。</p><h3 id="高级-架构层面的优化" tabindex="-1">高级：架构层面的优化 <a class="header-anchor" href="#高级-架构层面的优化" aria-label="Permalink to “高级：架构层面的优化”">​</a></h3><p>学习<strong>分库分表</strong>、<strong>Redis 缓存</strong>、<strong>搜索引擎优化</strong>等架构知识。</p><p>这些是解决大规模数据场景的必备技能，也是高级工程师的核心竞争力。</p><hr><h2 id="延伸思考" tabindex="-1">延伸思考 <a class="header-anchor" href="#延伸思考" aria-label="Permalink to “延伸思考”">​</a></h2><p>数据库优化有个「80/20 法则」：80% 的性能问题可以通过 20% 的优化手段解决。</p><p>这条法则告诉我们：<strong>不要过度优化，先解决最明显的问题。</strong></p><p>一条缺失的索引、一个不合理的 JOIN、一个深分页查询——这些往往是性能问题的罪魁祸首。</p><p>掌握了 SQL 优化和 MySQL 调优，你就解决了大部分问题。至于分库分表、NoSQL 等架构优化，那是后续进阶的内容。</p><p><strong>记住：先把简单的做好，再考虑复杂的。</strong></p>',49)])])}const f=e(h,[["render",i]]);export{b as __pageData,f as default};
